B.IW=s(["50%","65%","87%","95%"],t.s)
B.NX=new A.aD("What percentage of all strokes are ischemic in origin?",B.IW,2,"Approximately 87% of all strokes are ischemic, with the remainder being hemorrhagic (10% intracerebral, 3% subarachnoid).")
