B.Jo=s(["Anterior cerebral artery","Posterior cerebral artery","Middle cerebral artery","Basilar artery"],t.s)
B.NP=new A.aD("The lenticulostriate arteries are branches of which vessel?",B.Jo,2,"The lenticulostriate arteries are penetrating branches of the M1 segment of the MCA. They supply the putamen, globus pallidus, and internal capsule. Occlusion produces lacunar infarcts.")
B.HZ=s(["Middle cerebral artery","Posterior cerebral artery","Anterior cerebral artery","Anterior choroidal artery"],t.s)
