B.NB=new A.aD("Silent aspiration is defined as aspiration without which response?",B.H3,1,"Silent aspiration is penetration of material below the vocal folds without triggering a cough reflex. It is particularly dangerous because it is clinically undetectable at bedside and occurs in up to 40-70% of dysphagic stroke patients.")
B.Gs=s(["First 24 hours","First week","First 30 days","First year"],t.s)
B.ND=new A.aD("Aspiration pneumonia is the leading cause of death in which time period after stroke?",B.Gs,2,"Aspiration pneumonia is a leading cause of death within the first 30 days after stroke. Dysphagia screening should be performed before any oral intake to reduce aspiration risk.")
B.J_=s(["Fluent speech with impaired comprehension","Non-fluent speech with relatively preserved comprehension","Fluent speech with preserved comprehension but impaired repetition","Non-fluent speech with impaired comprehension"],t.s)
B.Nf=new A.aD("Broca aphasia is characterized by which of the following?",B.J_,1,"Broca (expressive/non-fluent) aphasia features effortful, telegraphic, non-fluent speech with relatively preserved auditory comprehension. The lesion is in the posterior inferior frontal gyrus (Brodmann areas 44-45) of the dominant hemisphere.")
B.HI=s(["Inferior frontal gyrus","Superior temporal gyrus (posterior)","Angular gyrus","Supplementary motor area"],t.s)
