B.Jr=s(["Broca aphasia","Wernicke aphasia","Transcortical motor aphasia","Conduction aphasia"],t.s)
B.Nq=new A.aD("Which type of aphasia features fluent speech, impaired comprehension, AND impaired repetition?",B.Jr,1,"Wernicke aphasia features fluent speech (often with paraphasias), impaired comprehension, and impaired repetition. Transcortical aphasias (motor and sensory) have preserved repetition. Conduction aphasia has impaired repetition but preserved comprehension.")
B.J7=s(["Broca area","Wernicke area","Arcuate fasciculus","Angular gyrus"],t.s)
