o=A.b7(A.a(["Subtype","Percentage","Description"],b),A.a([A.a(["Large artery atherosclerosis","~20-25%","Stenosis >50% of major cerebral artery or branch"],b),A.a(["Cardioembolism","~20-25%","Cardiac source identified (AFib, valvular disease, etc.)"],b),A.a(["Small vessel occlusion (lacunar)","~20-25%","Small deep infarct <15 mm with compatible syndrome"],b),A.a(["Stroke of other determined etiology","~5%","Dissection, vasculitis, hypercoagulable state, etc."],b),A.a(["Stroke of undetermined etiology (cryptogenic)","~25-30%","No cause identified despite complete workup, or multiple causes"],b)],p),"TOAST Classification of Ischemic Stroke")
