l=A.b7(A.a(["Feature","Thrombotic","Embolic"],b),A.a([A.a(["Onset","Gradual, stuttering, during sleep","Sudden, maximal deficit at onset, during activity"],b),A.a(["Preceding TIAs","Common, same territory","Less common"],b),A.a(["Deficit progression","Stepwise worsening over hours-days","Maximal at onset, may improve"],b),A.a(["Hemorrhagic transformation","Less common","More common (reperfusion of damaged tissue)"],b),A.a(["Multiple territories","Usually single territory","May affect multiple territories"],b),A.a(["Underlying cause","Local atherosclerosis","Distant source (cardiac, aortic, arterial)"],b)],p),"Thrombotic vs Embolic Stroke")
k=A.h(h)
