m=t.F
o=A.b4(A.a([g,f,e,q,p,A.a0(A.h(h),A.a(["IPC devices \u2014 mainstay (start on admission)","Pharmacologic prophylaxis delayed until hematoma is stable","Typically start LMWH at 48-72 hours if no hematoma expansion","Some centers wait up to 7-14 days","Early mobilization when medically stable","IVC filter \u2014 rarely indicated, only for proven DVT when anticoagulation contraindicated"],d),o,"DVT Prophylaxis \u2014 Hemorrhagic Stroke"),A.b7(A.a(["Test","Use","Key Points"],d),A.a([A.a(["Duplex ultrasound","First-line for DVT","High sensitivity for proximal DVT, lower for calf DVT"],d),A.a(["D-dimer","Screening","High NPV \u2014 useful to rule OUT DVT. Often elevated poststroke"],d),A.a(["CT pulmonary angiography","Gold standard for PE","Rapid, widely available, high sensitivity/specificity"],d),A.a(["V/Q scan","Alternative for PE","When CTA contraindicated (renal insufficiency, contrast allergy)"],d),A.a(["Venography","Historical gold standard for DVT","Rarely used \u2014 invasive, replaced by ultrasound"],d)],n),"DVT/PE Diagnosis")],m),"DVT/VTE")
p=A.aS("Bladder & Bowel Dysfunction After Stroke")
q=A.b2("Urinary incontinence affects 50-70% of stroke patients in the first month and is a strong negative predictor of functional outcome and discharge disposition. Bowel incontinence occurs in approximately 31% of acute stroke patients. Understanding the neuroanatomy of bladder control is essential for management.",!0)
e=A.b7(A.a(["Type","Mechanism","Urodynamics","Treatment"],d),A.a([A.a(["Uninhibited Neurogenic (Spastic)","Loss of cortical inhibition of pontine micturition center (UMN lesion)","Detrusor hyperreflexia \u2014 involuntary contractions at low volumes","Timed voiding, anticholinergics (oxybutynin), behavioral training"],d),A.a(["Areflexic (Flaccid)","Acute stage \u2014 spinal shock equivalent or detrusor underactivity","Detrusor areflexia \u2014 large volumes, overflow incontinence","Intermittent catheterization, Crede/Valsalva (caution)"],d),A.a(["Detrusor-Sphincter Dyssynergia","Incoordination of detrusor contraction and sphincter relaxation","High pressures, incomplete emptying, UTI risk","Alpha-blocker (tamsulosin), intermittent catheterization"],d)],n),"Bladder Types After Stroke")
f=A.ag("Most Common Bladder Type After Stroke","The most common bladder dysfunction after stroke is the UNINHIBITED neurogenic bladder (detrusor hyperreflexia) because stroke is an UPPER motor neuron lesion. The cortical micturition center (medial frontal lobe) normally inhibits the pontine micturition reflex. When this inhibition is lost, the detrusor contracts involuntarily at low bladder volumes, causing urge incontinence with frequency and urgency.")
g=A.h(i)
g=A.a0(A.h(h),A.a(["Remove indwelling catheter as soon as possible (within 24-48 hours)","Catheter-associated UTI is a major complication","Timed voiding schedule every 2-4 hours","Post-void residual (PVR) monitoring \u2014 if >150 mL, consider intermittent cath","Intermittent catheterization preferred over indwelling catheter","Anticholinergics for detrusor hyperreflexia (oxybutynin, tolterodine)","Side effects: dry mouth, constipation, confusion (especially in elderly)","Behavioral strategies: fluid management, prompted voiding, pelvic floor exercises"],d),g,"Bladder Management Principles")
