l=A.h(h)
l=A.bv(A.h(g),"Therapy services delivered in the patient's home. Requires homebound status.",B.EX,A.a(['Patient must be "homebound" (leaving home is a taxing effort)',"PT, OT, SLP, nursing, social work, and aide services available","Physician must certify need and create plan of care","Typically 2-3 visits per week per discipline","Focus on functional independence in actual home environment","Environmental assessment and modification","Caregiver training in the home setting","Bridge between inpatient rehab and outpatient"],c),l,"Home Health")
k=A.h(h)
k=A.b4(A.a([e,f,n,m,l,A.bv(A.h(g),"Clinic-based therapy services for patients who can travel to the facility.",B.EU,A.a(["Patient able to travel to clinic","Day rehabilitation programs: intensive (3-6 hours/day)","Standard outpatient: 1-3 sessions per week","Continued goal-directed therapy after inpatient rehab","May continue for months to years after stroke","Medicare therapy caps have been repealed (MIPS threshold replaces)","Community re-integration focus"],c),k,"Outpatient Rehabilitation"),A.ag("Early Rehabilitation = Better Outcomes","Multiple studies demonstrate that early rehabilitation (initiated within 24-48 hours of medical stabilization) leads to better functional outcomes, shorter hospital stays, and lower mortality. However, the AVERT trial showed that VERY early high-dose mobilization (<24 hours) may be harmful. Current recommendation: begin rehabilitation within 24-48 hours with graduated intensity, avoiding aggressive early high-dose mobilization."),A.b7(A.a(["Criterion","IRF","SNF","Home Health"],c),A.a([A.a(["Therapy tolerance","3 hrs/day","1-2 hrs/day","Variable"],c),A.a(["Medical stability","Required","More complex OK","Stable"],c),A.a(["Supervision need","24-hour available","24-hour nursing","Caregiver or independent"],c),A.a(["Therapy disciplines",">=2 required",">=1",">=1"],c),A.a(["MD supervision","3x/week face-to-face","Monthly","Certifying physician"],c),A.a(["Avg LOS","15-17 days","21-35 days","Weeks to months"],c),A.a(["Best for","Moderate-severe, motivated","Cannot tolerate IRF intensity","Homebound, functional plateau"],c)],p),"Rehabilitation Setting Selection Guide")],o),"Rehab Settings")
l=A.aS("Community Reintegration & Long-Term Outcomes")
