p=A.b7(A.a(["Outcome","Percentage","Notes"],c),A.a([A.a(["Independent in basic ADLs","50-70%","At 6 months poststroke"],c),A.a(["Community ambulation","50-60%","With or without assistive device"],c),A.a(["Return to work","25-50%","Highly variable, depends on job demands"],c),A.a(["Return to driving","30-50%","Requires formal driving evaluation"],c),A.a(["Persistent depression","30-50%","Ongoing screening needed"],c),A.a(["Recurrent stroke within 5 years","25-30%","Secondary prevention is critical"],c),A.a(["Caregiver burden/burnout","30-50%","Caregiver support programs essential"],c)],p),"Long-Term Functional Outcomes")
